('additional-maths:5-3-trigonometric-identities:misc:8fc322e9', 'additional-maths', 'additional-maths:5-3-trigonometric-identities', '5.3 Trigonometric Identities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \\( \\tan\\theta = \\dfrac{\\cos\\theta}{\\sin\\theta} \\)</p><p><strong>✅ The correct idea:</strong> The quotient identity is \\( \\tan\\theta \\equiv \\frac{\\sin\\theta}{\\cos\\theta} \\) — sine over cosine. A weak answer flips it; a strong answer checks with \\( \\tan45^\\circ = 1 = \\frac{\\sin45^\\circ}{\\cos45^\\circ} \\).</p>", "question": "Which is the correct quotient identity?", "options": ["\\( \\tan\\theta \\equiv \\frac{\\sin\\theta}{\\cos\\theta} \\)", "\\( \\tan\\theta \\equiv \\frac{\\cos\\theta}{\\sin\\theta} \\)", "\\( \\tan\\theta \\equiv \\sin\\theta\\cos\\theta \\)", "\\( \\tan\\theta \\equiv \\sin\\theta + \\cos\\theta \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\tan\\theta \\) is sine over cosine."}'::jsonb),
('additional-maths:5-3-trigonometric-identities:misc:1a1678a9', 'additional-maths', 'additional-maths:5-3-trigonometric-identities', '5.3 Trigonometric Identities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Given \\( \\cos\\theta = \\tfrac{1}{3} \\) with \\( \\theta \\) acute, \\( \\sin\\theta \\approx 0.94 \\)</p><p><strong>✅ The correct idea:</strong> The question wants an EXACT value: \\( \\sin\\theta = \\frac{2\\sqrt{2}}{3} \\). A weak answer rounds to a decimal (0 marks on an ''exact'' question); a strong answer leaves the surd (and may add the decimal only as a check).</p>", "question": "Given \\( \\cos\\theta = \\tfrac{1}{3} \\), \\( \\theta \\) acute, the exact \\( \\sin\\theta \\) is:", "options": ["\\( \\dfrac{2\\sqrt{2}}{3} \\)", "\\( 0.94 \\)", "\\( \\dfrac{8}{9} \\)", "\\( 0.9 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\sin^2\\theta = 1 - \\tfrac{1}{9} = \\tfrac{8}{9} \\Rightarrow \\sin\\theta = \\frac{2\\sqrt{2}}{3} \\); a decimal is not exact."}'::jsonb),
('additional-maths:5-3-trigonometric-identities:misc:2dcbd025', 'additional-maths', 'additional-maths:5-3-trigonometric-identities', '5.3 Trigonometric Identities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Given \\( \\sin\\theta = -0.6 \\) with \\( \\theta \\) in the third quadrant, \\( \\cos\\theta = +0.8 \\)</p><p><strong>✅ The correct idea:</strong> In the third quadrant \\( \\cos\\theta \\) is NEGATIVE, so \\( \\cos\\theta = -0.8 \\). A weak answer ignores the quadrant and takes the positive root; a strong answer states the quadrant and picks the sign to match.</p>", "question": "\\( \\sin\\theta = -0.6 \\), \\( \\theta \\) in the third quadrant. \\( \\cos\\theta = \\)", "options": ["\\( -0.8 \\)", "\\( +0.8 \\)", "\\( -0.6 \\)", "\\( 0.36 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\cos^2\\theta = 1 - 0.36 = 0.64 \\Rightarrow \\cos\\theta = \\pm0.8 \\); the third quadrant makes it \\( -0.8 \\)."}'::jsonb),
('additional-maths:5-3-trigonometric-identities:misc:182f60aa', 'additional-maths', 'additional-maths:5-3-trigonometric-identities', '5.3 Trigonometric Identities', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> From \\( \\cos^2\\theta = \\tfrac{16}{25} \\), conclude \\( \\cos\\theta = \\tfrac{16}{25} \\)</p><p><strong>✅ The correct idea:</strong> You still have to take the square root: \\( \\cos\\theta = \\pm\\frac{4}{5} \\), then choose the sign for the quadrant. A weak answer stops at \\( \\cos^2\\theta \\); a strong answer roots it and resolves the \\( \\pm \\).</p>", "question": "\\( \\cos^2\\theta = \\tfrac{16}{25} \\). Before choosing a sign, \\( \\cos\\theta = \\)", "options": ["\\( \\pm\\tfrac{4}{5} \\)", "\\( \\tfrac{16}{25} \\)", "\\( \\tfrac{8}{25} \\)", "\\( \\tfrac{4}{25} \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\sqrt{\\tfrac{16}{25}} = \\tfrac{4}{5} \\), and the root is \\( \\pm \\) until the quadrant decides."}'::jsonb),
('additional-maths:5-3-trigonometric-identities:tips:03dda54c', 'additional-maths', 'additional-maths:5-3-trigonometric-identities', '5.3 Trigonometric Identities', 'tips', 'mcq', 1, '{"readingTitle": "explain — The ''exact'' command word", "reading": "<p><strong>0 marks:</strong> \\( \\sin\\theta = 0.94 \\) on an \"exact\" question — a decimal only.</p><p><strong>Full marks:</strong> \\( \\sin\\theta = \\dfrac{2\\sqrt{2}}{3} \\). If unsure, write the exact surd <em>and</em> the decimal — the surd earns the marks and the decimal never loses them.</p>", "question": "On an ''exact'' question, which is safest?", "options": ["Give the surd form (optionally with the decimal)", "Give only the decimal", "Round to 2 d.p.", "Give only the decimal to 3 s.f."]}'::jsonb, '{"answer": 0, "explain": "The exact surd/fraction form is required; adding a decimal alongside is harmless."}'::jsonb),
('additional-maths:5-3-trigonometric-identities:tips:86d3d3de', 'additional-maths', 'additional-maths:5-3-trigonometric-identities', '5.3 Trigonometric Identities', 'tips', 'mcq', 1, '{"readingTitle": "tip — Proving an identity — the show-that ladder", "reading": "<p><strong>0 marks:</strong> writing the identity and \"cross-multiplying\" across the \\( \\equiv \\) — that assumes the result.</p><p><strong>Partial:</strong> reaching LHS \\( = \\dfrac{\\sin^2\\theta + \\cos^2\\theta}{\\sin\\theta\\cos\\theta} \\) but stopping there.</p><p><strong>Full marks:</strong> continue \\( = \\dfrac{1}{\\sin\\theta\\cos\\theta} = \\) RHS, <strong>and write \"as required\"</strong>. The concluding line is a real mark.</p>", "question": "In a ''show that'' proof, the final concluding line is:", "options": ["A genuine mark that is often forgotten", "Optional decoration", "Only needed for long proofs", "Never credited"]}'::jsonb, '{"answer": 0, "explain": "Examiners award a mark for reaching the printed result and stating it is proved."}'::jsonb),
('additional-maths:5-3-trigonometric-identities:tips:7da48e50', 'additional-maths', 'additional-maths:5-3-trigonometric-identities', '5.3 Trigonometric Identities', 'tips', 'mcq', 1, '{"readingTitle": "tip — Let the quadrant choose the sign", "reading": "<p><strong>0 marks (or lost accuracy):</strong> giving both signs, or the wrong sign, after a square root.</p><p><strong>Full marks:</strong> state the quadrant, recall which ratios are positive there (Q1 all, Q2 sin, Q3 tan, Q4 cos), and pick the matching sign — e.g. \\( \\theta \\) in Q3 with \\( \\sin\\theta = -\\tfrac{3}{5} \\) gives \\( \\cos\\theta = -\\tfrac{4}{5} \\).</p>", "question": "After \\( \\cos\\theta = \\pm\\tfrac{4}{5} \\), how do you fix the sign?", "options": ["Use the quadrant \\( \\theta \\) lies in", "Always choose positive", "Always choose negative", "Leave it as \\( \\pm \\)"]}'::jsonb, '{"answer": 0, "explain": "The quadrant determines whether \\( \\cos\\theta \\) is positive or negative."}'::jsonb),
