('additional-maths:5-4-trigonometric-equations:mcq:afab5981', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'mcq', 'mcq', 1, '{"question": "To solve \\( 2\\cos^2\\theta + 3\\cos\\theta + 1 = 0 \\), the best first step is to:", "options": ["Factorise it as a quadratic in \\( \\cos\\theta \\)", "Replace \\( \\cos^2\\theta \\) with \\( 1 + \\sin^2\\theta \\)", "Take \\( \\cos^{-1} \\) of every term", "Divide through by \\( \\cos\\theta \\)"]}'::jsonb, '{"answer": 0, "explain": "It is already a quadratic in \\( \\cos\\theta \\): \\( (2\\cos\\theta+1)(\\cos\\theta+1)=0 \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:mcq:7480d5e8', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'mcq', 'mcq', 1, '{"question": "Solving \\( 12\\cos^2\\theta + \\sin\\theta = 11 \\) leads to \\( 12\\sin^2\\theta - \\sin\\theta - 1 = 0 \\). What are the values of \\( \\sin\\theta \\)?", "options": ["\\( \\sin\\theta = \\tfrac{1}{3} \\) or \\( -\\tfrac{1}{4} \\)", "\\( \\sin\\theta = \\tfrac{1}{4} \\) or \\( -\\tfrac{1}{3} \\)", "\\( \\sin\\theta = \\tfrac{1}{2} \\) or \\( -1 \\)", "\\( \\sin\\theta = 1 \\) or \\( -1 \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( (3\\sin\\theta - 1)(4\\sin\\theta + 1) = 0 \\), so \\( \\sin\\theta = \\tfrac{1}{3} \\) or \\( \\sin\\theta = -\\tfrac{1}{4} \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:mcq:a5ef240b', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'mcq', 'mcq', 1, '{"question": "\\( \\sin\\theta = -0.5 \\) for \\( 0^\\circ \\le \\theta \\le 360^\\circ \\). The calculator gives \\( -30^\\circ \\). The in-range solutions are:", "options": ["\\( 210^\\circ,\\ 330^\\circ \\)", "\\( 30^\\circ,\\ 150^\\circ \\)", "\\( 210^\\circ \\) only", "\\( 30^\\circ,\\ 330^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\sin \\) is negative in the 3rd and 4th quadrants: \\( 180^\\circ + 30^\\circ = 210^\\circ \\) and \\( 360^\\circ - 30^\\circ = 330^\\circ \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:mcq:f1c13ed1', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'mcq', 'mcq', 1, '{"question": "Why is it wrong to solve \\( \\tan 2x = 0.5 \\) by writing \\( \\tan x = 0.25 \\)?", "options": ["You cannot halve the angle inside a trig ratio — \\( \\tan 2x \\ne 2\\tan x \\)", "0.25 is not in range", "\\( \\tan \\) has no inverse", "You must use \\( \\cos \\) instead"]}'::jsonb, '{"answer": 0, "explain": "The angle multiple stays inside the ratio; you solve for \\( 2x \\) over an expanded interval, then divide the results by 2."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:mcq:3764f7f5', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'mcq', 'mcq', 1, '{"question": "For \\( 0^\\circ \\le \\theta \\le 360^\\circ \\), how many solutions does \\( \\sin\\theta = k \\) have when \\( 0 < k < 1 \\)?", "options": ["Two", "One", "Three", "Four"]}'::jsonb, '{"answer": 0, "explain": "The line \\( y = k \\) cuts one full sine wave twice, giving the pair \\( \\alpha \\) and \\( 180^\\circ - \\alpha \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:tf:36b557c5', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'tf', 'tf', 1, '{"question": "The calculator''s \\( \\sin^{-1} \\) key gives every solution of \\( \\sin\\theta = k \\) in the interval."}'::jsonb, '{"answer": false, "explain": "It gives only the principal value; you use the graph''s symmetry (\\( 180^\\circ - \\alpha \\)) for the rest."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:tf:69ec4c52', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'tf', 'tf', 1, '{"question": "For \\( \\cos\\theta = k \\), the two solutions in \\( 0^\\circ \\)–\\( 360^\\circ \\) are \\( \\alpha \\) and \\( 360^\\circ - \\alpha \\)."}'::jsonb, '{"answer": true, "explain": "The cosine graph is symmetric about \\( 0^\\circ \\)/\\( 360^\\circ \\), giving the partner \\( 360^\\circ - \\alpha \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:tf:28f47c2b', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'tf', 'tf', 1, '{"question": "\\( \\tan\\theta = k \\) has solutions \\( \\alpha \\) and \\( 180^\\circ - \\alpha \\)."}'::jsonb, '{"answer": false, "explain": "That is the sine rule. For \\( \\tan \\) the partner is \\( \\alpha + 180^\\circ \\), because \\( \\tan \\) has period \\( 180^\\circ \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:tf:2a7b8c59', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'tf', 'tf', 1, '{"question": "Solving \\( \\cos 2\\theta = 0.6 \\) for \\( 0^\\circ \\le \\theta \\le 360^\\circ \\) gives four solutions."}'::jsonb, '{"answer": true, "explain": "Over the doubled interval \\( 0^\\circ \\)–\\( 720^\\circ \\), \\( \\cos 2\\theta = 0.6 \\) has four solutions, so four values of \\( \\theta \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:tf:490b1936', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'tf', 'tf', 1, '{"question": "You can solve \\( \\tan 2x = 0.5 \\) by first writing \\( \\tan x = 0.25 \\)."}'::jsonb, '{"answer": false, "explain": "You cannot halve the angle inside a ratio; solve for \\( 2x \\) over \\( 0^\\circ \\)–\\( 720^\\circ \\), then divide the answers by 2."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:tf:c676ae78', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'tf', 'tf', 1, '{"question": "\\( 12\\cos^2\\theta + \\sin\\theta = 11 \\) becomes a quadratic once \\( \\cos^2\\theta \\) is replaced by \\( 1 - \\sin^2\\theta \\)."}'::jsonb, '{"answer": true, "explain": "It gives \\( 12\\sin^2\\theta - \\sin\\theta - 1 = 0 \\), a quadratic in \\( \\sin\\theta \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:tf:4241de0f', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'tf', 'tf', 1, '{"question": "On a ''detailed reasoning'' question, writing the correct final angles straight from the calculator earns full marks."}'::jsonb, '{"answer": false, "explain": "DR requires the analytical working to be shown; an unsupported calculator answer scores 0 even if correct."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:tf:1ea5a480', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'tf', 'tf', 1, '{"question": "For \\( 0^\\circ \\le \\theta \\le 360^\\circ \\), a single \\( \\sin\\theta = k \\) with \\( 0 < k < 1 \\) always has exactly two solutions."}'::jsonb, '{"answer": true, "explain": "The line \\( y = k \\) crosses one full sine wave twice, giving the pair \\( \\alpha \\) and \\( 180^\\circ - \\alpha \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:learn:cb5639a4', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'learn', 'mcq', 1, '{"readingTitle": "How do you solve a trig equation in a given interval?", "reading": "<p>A <strong>trigonometric equation</strong> such as \\( \\sin\\theta = 0.4 \\) has infinitely many solutions, because the graphs of \\( \\sin \\), \\( \\cos \\) and \\( \\tan \\) repeat. The exam always fixes an <strong>interval</strong> (e.g. \\( 0^\\circ \\le \\theta \\le 360^\\circ \\)) and asks for <strong>all</strong> the solutions inside it.</p>\n            <ul>\n              <li><strong>Step 1 — principal value.</strong> Put the equation in the form \\( \\sin\\theta = k \\) (or \\( \\cos\\theta = k \\), \\( \\tan\\theta = k \\)) and use \\( \\sin^{-1} \\), \\( \\cos^{-1} \\) or \\( \\tan^{-1} \\) on the calculator. This gives one angle, the <strong>principal value</strong>.</li>\n              <li><strong>Step 2 — use the symmetry.</strong> The calculator only ever gives you one answer; you must use the shape of the graph (or the <strong>CAST</strong> diagram) to find every other solution in the interval.</li>\n              <li><strong>Step 3 — keep only those in range.</strong> Add or subtract full turns (\\( 360^\\circ \\) for \\( \\sin \\)/\\( \\cos \\), \\( 180^\\circ \\) for \\( \\tan \\)) to sweep the whole interval, then discard any angle outside it.</li>\n            </ul>\n            <p>Because sine and cosine graphs are symmetric, solutions come in <strong>pairs</strong> across a full \\( 360^\\circ \\) — three solutions to a single \\( \\sin\\theta = k \\) or \\( \\cos\\theta = k \\) in \\( 0^\\circ \\)–\\( 360^\\circ \\) is a sign you have made a slip.</p>", "question": "Why is the calculator value alone not a full answer?", "options": ["It gives only one angle; the graph''s symmetry has other solutions in the interval", "It is always wrong", "It gives every solution automatically", "It works only for \\( \\tan \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\sin^{-1} \\), \\( \\cos^{-1} \\), \\( \\tan^{-1} \\) each return a single principal value — you use the graph/CAST to find the rest in range."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:learn:a3462f58', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'learn', 'mcq', 1, '{"readingTitle": "Which symmetry rule gives the other solutions?", "reading": "<p>Learn one rule for each ratio. Take the calculator''s principal value \\( \\alpha \\), then generate the partner and repeat every full period until you leave the interval.</p>\n            <table class=\"worked\">\n              <tr><td><strong>\\( \\sin\\theta = k \\):</strong> solutions are \\( \\theta = \\alpha \\) and \\( \\theta = 180^\\circ - \\alpha \\), then add \\( 360^\\circ \\) as needed.</td></tr>\n              <tr><td><strong>\\( \\cos\\theta = k \\):</strong> solutions are \\( \\theta = \\alpha \\) and \\( \\theta = 360^\\circ - \\alpha \\), then add \\( 360^\\circ \\) as needed.</td></tr>\n              <tr><td><strong>\\( \\tan\\theta = k \\):</strong> solutions are \\( \\theta = \\alpha \\) and \\( \\theta = \\alpha + 180^\\circ \\) (tan repeats every \\( 180^\\circ \\)).</td></tr>\n            </table>\n            <p>The sine graph below shows why \\( \\sin\\theta = 0.4 \\) has two solutions in \\( 0^\\circ \\)–\\( 360^\\circ \\): the horizontal line \\( y = 0.4 \\) cuts the curve twice, at \\( \\theta \\approx 23.6^\\circ \\) and its mirror image \\( 180^\\circ - 23.6^\\circ = 156.4^\\circ \\).</p>\n            <svg viewBox=\"0 0 430 210\" role=\"img\" aria-label=\"Graph of y = sin theta from 0 to 360 degrees with the line y = 0.4 crossing it twice\" style=\"width:100%;max-width:430px;height:auto;color:var(--ink,#333)\">\n              <line x1=\"40\" y1=\"100\" x2=\"410\" y2=\"100\" stroke=\"currentColor\" stroke-width=\"1\" opacity=\"0.5\"/>\n              <line x1=\"40\" y1=\"30\" x2=\"40\" y2=\"180\" stroke=\"currentColor\" stroke-width=\"1\" opacity=\"0.5\"/>\n              <polyline points=\"40,100 70,65 100,39 130,30 160,39 190,65 220,100 250,135 280,161 310,170 340,161 370,135 400,100\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\"/>\n              <line x1=\"40\" y1=\"72\" x2=\"400\" y2=\"72\" stroke=\"#4c9aff\" stroke-width=\"1.5\" stroke-dasharray=\"5 4\"/>\n              <line x1=\"63.6\" y1=\"72\" x2=\"63.6\" y2=\"100\" stroke=\"#4c9aff\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/>\n              <line x1=\"196.4\" y1=\"72\" x2=\"196.4\" y2=\"100\" stroke=\"#4c9aff\" stroke-width=\"1\" stroke-dasharray=\"3 3\"/>\n              <circle cx=\"63.6\" cy=\"72\" r=\"3.5\" fill=\"#4c9aff\"/>\n              <circle cx=\"196.4\" cy=\"72\" r=\"3.5\" fill=\"#4c9aff\"/>\n              <text x=\"405\" y=\"68\" font-size=\"11\" fill=\"#4c9aff\">y = 0.4</text>\n              <text x=\"46\" y=\"112\" font-size=\"10\" fill=\"currentColor\">23.6°</text>\n              <text x=\"176\" y=\"112\" font-size=\"10\" fill=\"currentColor\">156.4°</text>\n              <text x=\"214\" y=\"97\" font-size=\"10\" fill=\"currentColor\" opacity=\"0.7\">180°</text>\n              <text x=\"392\" y=\"97\" font-size=\"10\" fill=\"currentColor\" opacity=\"0.7\">360°</text>\n            </svg>", "question": "You solve \\( \\cos\\theta = 0.7 \\) and the calculator gives \\( 45.6^\\circ \\). What is the second solution in \\( 0^\\circ \\)–\\( 360^\\circ \\)?", "options": ["\\( 314.4^\\circ \\)", "\\( 134.4^\\circ \\)", "\\( 225.6^\\circ \\)", "\\( 225.0^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "For \\( \\cos \\) the partner is \\( 360^\\circ - \\alpha = 360^\\circ - 45.6^\\circ = 314.4^\\circ \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:learn:8b767b2e', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'learn', 'mcq', 1, '{"readingTitle": "Worked example — solving sin, cos and tan equations", "reading": "<p><strong>(A) Solve \\( \\sin\\theta = 0.4 \\) for \\( 0^\\circ \\le \\theta \\le 360^\\circ \\) (1 dp).</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Principal value: \\( \\theta = \\sin^{-1}(0.4) = 23.578\\ldots = 23.6^\\circ \\).</td></tr>\n              <tr><td>2. Sine partner: \\( 180^\\circ - 23.578^\\circ = 156.4^\\circ \\).</td></tr>\n              <tr><td>3. Both lie in range, so \\[ \\theta = 23.6^\\circ,\\ 156.4^\\circ. \\]</td></tr>\n            </table>\n            <p><strong>(B) Solve \\( \\cos\\theta = 0.5 \\) for \\( 0^\\circ \\le \\theta \\le 360^\\circ \\).</strong> Principal value \\( \\cos^{-1}(0.5) = 60^\\circ \\); cosine partner \\( 360^\\circ - 60^\\circ = 300^\\circ \\). So \\( \\theta = 60^\\circ,\\ 300^\\circ \\).</p>\n            <p><strong>(C) Solve \\( \\tan\\theta = 2 \\) for \\( 0^\\circ \\le \\theta \\le 360^\\circ \\) (1 dp).</strong> Principal value \\( \\tan^{-1}(2) = 63.4^\\circ \\); add \\( 180^\\circ \\) to get \\( 243.4^\\circ \\). So \\( \\theta = 63.4^\\circ,\\ 243.4^\\circ \\).</p>\n            <p>If \\( k \\) is <strong>negative</strong> the calculator returns a negative principal value — add \\( 360^\\circ \\) (or \\( 180^\\circ \\) for \\( \\tan \\)) to bring it into range before finding the partner.</p>", "question": "Solve \\( \\tan\\theta = 0.75 \\) for \\( 0^\\circ \\le \\theta \\le 360^\\circ \\) (1 dp).", "options": ["\\( 36.9^\\circ,\\ 216.9^\\circ \\)", "\\( 36.9^\\circ \\) only", "\\( 36.9^\\circ,\\ 143.1^\\circ \\)", "\\( 36.9^\\circ,\\ 323.1^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "\\( \\tan^{-1}(0.75) = 36.9^\\circ \\); \\( \\tan \\) repeats every \\( 180^\\circ \\), so the partner is \\( 36.9^\\circ + 180^\\circ = 216.9^\\circ \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:learn:60e70825', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'learn', 'mcq', 1, '{"readingTitle": "How do you solve a multiple-angle equation like tan 2x = 0.5?", "reading": "<p>When the angle inside the ratio is a <strong>multiple</strong> (\\( 2\\theta \\), \\( 3x \\), …), solve for that whole multiple angle first — over an <strong>expanded interval</strong> — and divide only at the end.</p>\n            <ul>\n              <li>If \\( 0^\\circ \\le x \\le 360^\\circ \\), then \\( 2x \\) runs over \\( 0^\\circ \\le 2x \\le 720^\\circ \\). You must find every solution across that <strong>doubled</strong> interval.</li>\n              <li>This is the classic trap: doubling the interval <strong>doubles the number of solutions</strong>. A \\( \\sin\\theta = k \\) has two solutions in \\( 360^\\circ \\), so \\( \\sin 2\\theta = k \\) has <strong>four</strong> in \\( 360^\\circ \\).</li>\n            </ul>\n            <p><strong>Worked example — solve \\( \\tan 2x = 0.5 \\) for \\( 0^\\circ \\le x \\le 360^\\circ \\) (1 dp).</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Let \\( u = 2x \\), so \\( 0^\\circ \\le u \\le 720^\\circ \\).</td></tr>\n              <tr><td>2. Principal value: \\( u = \\tan^{-1}(0.5) = 26.565^\\circ \\).</td></tr>\n              <tr><td>3. Add \\( 180^\\circ \\) repeatedly while \\( u \\le 720^\\circ \\): \\( u = 26.565^\\circ,\\ 206.565^\\circ,\\ 386.565^\\circ,\\ 566.565^\\circ \\).</td></tr>\n              <tr><td>4. Divide every value by 2: \\[ x = 13.3^\\circ,\\ 103.3^\\circ,\\ 193.3^\\circ,\\ 283.3^\\circ. \\]</td></tr>\n            </table>\n            <p><strong>Never</strong> solve \\( \\tan 2x = 0.5 \\) by writing \\( \\tan x = 0.25 \\) — you cannot halve inside a trig ratio. Expand the interval instead.</p>", "question": "For \\( \\cos 2\\theta = 0.5 \\) with \\( 0^\\circ \\le \\theta \\le 360^\\circ \\), over what interval must you first solve for \\( 2\\theta \\)?", "options": ["\\( 0^\\circ \\le 2\\theta \\le 720^\\circ \\)", "\\( 0^\\circ \\le 2\\theta \\le 360^\\circ \\)", "\\( 0^\\circ \\le 2\\theta \\le 180^\\circ \\)", "\\( 0^\\circ \\le 2\\theta \\le 90^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "Doubling the angle doubles the interval: \\( \\theta \\le 360^\\circ \\) means \\( 2\\theta \\le 720^\\circ \\), so you must sweep the full \\( 720^\\circ \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:learn:af920407', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'learn', 'mcq', 1, '{"readingTitle": "How do you solve an equation that hides a quadratic?", "reading": "<p>Some equations mix \\( \\sin^2\\theta \\) or \\( \\cos^2\\theta \\) with the first-power ratio. Use the identity \\( \\sin^2\\theta + \\cos^2\\theta = 1 \\) to write everything in <strong>one</strong> ratio, then it becomes a <strong>quadratic</strong>.</p>\n            <ul>\n              <li>If the odd term is \\( \\cos\\theta \\), replace \\( \\sin^2\\theta \\) with \\( 1 - \\cos^2\\theta \\).</li>\n              <li>If the odd term is \\( \\sin\\theta \\), replace \\( \\cos^2\\theta \\) with \\( 1 - \\sin^2\\theta \\).</li>\n              <li>Let \\( s = \\sin\\theta \\) (or \\( c = \\cos\\theta \\)), factorise or use the formula, then solve each resulting simple equation in range.</li>\n            </ul>\n            <p><strong>Worked example — solve \\( 2\\sin^2\\theta - 3\\cos\\theta - 3 = 0 \\) for \\( 0^\\circ \\le \\theta \\le 360^\\circ \\).</strong></p>\n            <table class=\"worked\">\n              <tr><td>1. Replace \\( \\sin^2\\theta \\): \\( 2(1 - \\cos^2\\theta) - 3\\cos\\theta - 3 = 0 \\).</td></tr>\n              <tr><td>2. Tidy: \\( -2\\cos^2\\theta - 3\\cos\\theta - 1 = 0 \\Rightarrow 2\\cos^2\\theta + 3\\cos\\theta + 1 = 0 \\).</td></tr>\n              <tr><td>3. Factorise: \\( (2\\cos\\theta + 1)(\\cos\\theta + 1) = 0 \\).</td></tr>\n              <tr><td>4. So \\( \\cos\\theta = -\\tfrac{1}{2} \\) or \\( \\cos\\theta = -1 \\).</td></tr>\n              <tr><td>5. \\( \\cos\\theta = -\\tfrac{1}{2} \\Rightarrow \\theta = 120^\\circ,\\ 240^\\circ \\); \\( \\cos\\theta = -1 \\Rightarrow \\theta = 180^\\circ \\).</td></tr>\n              <tr><td>6. All solutions: \\[ \\theta = 120^\\circ,\\ 180^\\circ,\\ 240^\\circ. \\]</td></tr>\n            </table>\n            <p>Always solve <strong>each</strong> value of the ratio for its own angles in range — one quadratic can produce three or four final answers.</p>", "question": "To solve \\( 12\\cos^2\\theta + \\sin\\theta = 11 \\), which substitution turns it into a quadratic in \\( \\sin\\theta \\)?", "options": ["\\( \\cos^2\\theta = 1 - \\sin^2\\theta \\)", "\\( \\cos^2\\theta = 1 + \\sin^2\\theta \\)", "\\( \\cos\\theta = 1 - \\sin\\theta \\)", "\\( \\sin^2\\theta = 1 + \\cos^2\\theta \\)"]}'::jsonb, '{"answer": 0, "explain": "From \\( \\sin^2\\theta + \\cos^2\\theta = 1 \\), \\( \\cos^2\\theta = 1 - \\sin^2\\theta \\); substituting leaves only \\( \\sin\\theta \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:learn:b6a2574b', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'learn', 'mcq', 1, '{"readingTitle": "How precisely must you give trig answers?", "reading": "<p>Read the command carefully — the required form changes the whole answer.</p>\n            <ul>\n              <li><strong>\"correct to 1 decimal place\"</strong> — give each angle as a rounded decimal, e.g. \\( 26.6^\\circ \\). Do not leave extra decimals; do not give exact surds.</li>\n              <li><strong>\"exact value\"</strong> — leave surds/fractions, e.g. \\( \\sin\\theta = \\tfrac{3\\sqrt{13}}{13} \\). A rounded decimal scores <strong>0</strong> here.</li>\n              <li><strong>\"you must show detailed reasoning\" (DR)</strong> — write every analytical step: identity used, quadratic formed, factors, each angle. A bare calculator solution scores <strong>0</strong> even if the numbers are right.</li>\n              <li>Give <strong>all</strong> solutions in the stated interval — a common lost mark is stopping after the first one. And give <strong>no</strong> extras outside the interval, or a \"list all\" mark can be withheld.</li>\n            </ul>\n            <p>A safe habit on a 1 dp question: carry the unrounded principal value in the calculator''s memory, generate every partner from it, and round only at the very end.</p>", "question": "A question says \"show detailed reasoning\" and \"1 decimal place\". A student writes just the four final angles from the calculator. What happens?", "options": ["They score 0 — DR requires the analytical working to be shown", "Full marks, the answers are right", "They lose one mark only", "It depends on rounding"]}'::jsonb, '{"answer": 0, "explain": "Under detailed reasoning, an unsupported calculator answer earns no marks even when correct — the method must be visible."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:misc:c92f0c71', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Giving \\( \\sin\\theta = 0.4 \\Rightarrow \\theta = 23.6^\\circ \\) as the only answer</p><p><strong>✅ The correct idea:</strong> The calculator gives one value; you must add all in-range solutions. A weak answer stops at \\( 23.6^\\circ \\); a strong answer also writes the partner \\( 180^\\circ - 23.6^\\circ = 156.4^\\circ \\).</p>", "question": "How many solutions does \\( \\sin\\theta = 0.4 \\) have in \\( 0^\\circ \\)–\\( 360^\\circ \\)?", "options": ["Two", "One", "Three", "Four"]}'::jsonb, '{"answer": 0, "explain": "\\( \\theta = 23.6^\\circ \\) and \\( 156.4^\\circ \\) — sine solutions come in a pair."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:misc:796fa4af', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Solving \\( \\sin 2\\theta = 0.5 \\) as if \\( 2\\theta \\) only runs up to \\( 360^\\circ \\)</p><p><strong>✅ The correct idea:</strong> You must double the interval. A weak answer solves \\( 2\\theta \\) over \\( 0^\\circ \\)–\\( 360^\\circ \\) and gives two answers; a strong answer uses \\( 0^\\circ \\)–\\( 720^\\circ \\) and finds all four.</p>", "question": "For \\( 0^\\circ \\le \\theta \\le 360^\\circ \\), \\( 2\\theta \\) ranges over:", "options": ["\\( 0^\\circ \\) to \\( 720^\\circ \\)", "\\( 0^\\circ \\) to \\( 360^\\circ \\)", "\\( 0^\\circ \\) to \\( 180^\\circ \\)", "\\( 0^\\circ \\) to \\( 1080^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "Doubling the angle doubles the interval, so you must sweep to \\( 720^\\circ \\)."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:misc:b7603f3b', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Writing \\( \\tan 2x = 0.5 \\Rightarrow \\tan x = 0.25 \\)</p><p><strong>✅ The correct idea:</strong> The angle multiple cannot be halved inside the ratio. A weak answer ''simplifies'' to \\( \\tan x = 0.25 \\); a strong answer solves \\( \\tan u = 0.5 \\) for \\( u = 2x \\) over \\( 0^\\circ \\)–\\( 720^\\circ \\), then divides by 2.</p>", "question": "The correct method for \\( \\tan 2x = 0.5 \\) is to:", "options": ["Solve for \\( 2x \\) over the doubled interval, then halve each answer", "Write \\( \\tan x = 0.25 \\)", "Take the square root", "Use \\( \\sin \\) instead"]}'::jsonb, '{"answer": 0, "explain": "Solve for the whole multiple angle first, then divide the results by 2."}'::jsonb),
('additional-maths:5-4-trigonometric-equations:misc:a9eed218', 'additional-maths', 'additional-maths:5-4-trigonometric-equations', '5.4 Trigonometric Equations', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> Answering an ''exact value'' trig question with \\( \\sin\\theta = 0.832 \\)</p><p><strong>✅ The correct idea:</strong> ''Exact'' forbids a rounded decimal. A weak answer rounds; a strong answer gives the surd form, e.g. \\( \\sin\\theta = \\tfrac{3\\sqrt{13}}{13} \\).</p>", "question": "Which is an ''exact'' value of \\( \\sin\\theta \\)?", "options": ["\\( \\tfrac{3\\sqrt{13}}{13} \\)", "\\( 0.832 \\)", "\\( 0.83 \\)", "about \\( 0.8 \\)"]}'::jsonb, '{"answer": 0, "explain": "Only the surd form \\( \\tfrac{3\\sqrt{13}}{13} \\) is exact; the decimals are approximations."}'::jsonb),
