('additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d:mcq:3b029a95', 'additional-maths', 'additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d', '5.5 Pythagoras and Trig in 2D and 3D', 'mcq', 'mcq', 1, '{"question": "A bearing must be written:", "options": ["Clockwise from north, with three figures (e.g. \\( 072^\\circ \\))", "Anticlockwise from north, with two figures", "Clockwise from east, with three figures", "As the acute angle to the nearest axis"]}'::jsonb, '{"answer": 0, "explain": "Bearings are measured clockwise from north and always given as three figures."}'::jsonb),
('additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d:mcq:b1f275a9', 'additional-maths', 'additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d', '5.5 Pythagoras and Trig in 2D and 3D', 'mcq', 'mcq', 1, '{"question": "The bearing of B from A is \\( 060^\\circ \\). The bearing of A from B is:", "options": ["\\( 240^\\circ \\)", "\\( 120^\\circ \\)", "\\( 300^\\circ \\)", "\\( 060^\\circ \\)"]}'::jsonb, '{"answer": 0, "explain": "The reverse bearing differs by \\( 180^\\circ \\): \\( 060 + 180 = 240^\\circ \\)."}'::jsonb),
('additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d:mcq:fc7a7999', 'additional-maths', 'additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d', '5.5 Pythagoras and Trig in 2D and 3D', 'mcq', 'mcq', 1, '{"question": "From a point \\( 100 \\) m horizontally from the foot of a \\( 20 \\) m mast, the angle of elevation of the top is:", "options": ["\\( \\tan^{-1}(20/100) = 11.3^\\circ \\)", "\\( \\tan^{-1}(100/20) = 78.7^\\circ \\)", "\\( \\sin^{-1}(20/100) = 11.5^\\circ \\)", "\\( \\cos^{-1}(20/100) \\)"]}'::jsonb, '{"answer": 0, "explain": "Elevation is measured from the horizontal: opposite = 20, adjacent = 100, \\( \\tan\\theta = 20/100 \\), \\( \\theta = 11.3^\\circ \\)."}'::jsonb),
('additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d:mcq:4bc270ce', 'additional-maths', 'additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d', '5.5 Pythagoras and Trig in 2D and 3D', 'mcq', 'mcq', 1, '{"question": "A ground triangle of bearings has no right angle. To find a missing side you should use:", "options": ["The sine or cosine rule", "Pythagoras'' theorem", "SOH-CAH-TOA directly", "The angle of elevation formula"]}'::jsonb, '{"answer": 0, "explain": "Pythagoras and SOH-CAH-TOA need a right angle; a general triangle needs the sine or cosine rule from 5.2."}'::jsonb),
('additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d:tf:8418cbf3', 'additional-maths', 'additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d', '5.5 Pythagoras and Trig in 2D and 3D', 'tf', 'tf', 1, '{"question": "The space diagonal of an \\( a\\times b\\times c \\) cuboid is \\( \\sqrt{a^2 + b^2 + c^2} \\)."}'::jsonb, '{"answer": true, "explain": "Pythagoras in 3D: the base diagonal is \\( \\sqrt{a^2+b^2} \\), then combine with the height \\( c \\) to get \\( \\sqrt{a^2+b^2+c^2} \\)."}'::jsonb),
('additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d:tf:347364aa', 'additional-maths', 'additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d', '5.5 Pythagoras and Trig in 2D and 3D', 'tf', 'tf', 1, '{"question": "In a 3D problem you should do trigonometry in three dimensions at once, without drawing a triangle."}'::jsonb, '{"answer": false, "explain": "You always isolate a single right-angled triangle in one plane and redraw it flat before using trig."}'::jsonb),
('additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d:tf:6f29cfbd', 'additional-maths', 'additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d', '5.5 Pythagoras and Trig in 2D and 3D', 'tf', 'tf', 1, '{"question": "The angle a line makes with the horizontal uses the vertical height as the opposite side."}'::jsonb, '{"answer": true, "explain": "Height is opposite, horizontal distance is adjacent, so \\( \\tan\\theta = \\text{height}/\\text{horizontal distance} \\)."}'::jsonb),
('additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d:tf:d6ebe37f', 'additional-maths', 'additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d', '5.5 Pythagoras and Trig in 2D and 3D', 'tf', 'tf', 1, '{"question": "The line of greatest slope runs parallel to the horizontal edges of the sloping face."}'::jsonb, '{"answer": false, "explain": "It runs perpendicular to them — straight up the slope, which is the steepest direction."}'::jsonb),
('additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d:tf:d6d8accb', 'additional-maths', 'additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d', '5.5 Pythagoras and Trig in 2D and 3D', 'tf', 'tf', 1, '{"question": "\\( \\tan^{-1}(20/80) \\) and \\( \\tan^{-1}(80/20) \\) give the same angle."}'::jsonb, '{"answer": false, "explain": "They are complementary: \\( 14.0^\\circ \\) (to the horizontal) and \\( 76.0^\\circ \\) (to the vertical), adding to \\( 90^\\circ \\)."}'::jsonb),
('additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d:tf:775cab33', 'additional-maths', 'additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d', '5.5 Pythagoras and Trig in 2D and 3D', 'tf', 'tf', 1, '{"question": "A bearing of \\( 060^\\circ \\) reversed becomes \\( 240^\\circ \\)."}'::jsonb, '{"answer": true, "explain": "Reverse bearings differ by \\( 180^\\circ \\): \\( 060 + 180 = 240^\\circ \\)."}'::jsonb),
('additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d:tf:bd8b2c95', 'additional-maths', 'additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d', '5.5 Pythagoras and Trig in 2D and 3D', 'tf', 'tf', 1, '{"question": "If a ground triangle has no right angle, Pythagoras will still find a missing side directly."}'::jsonb, '{"answer": false, "explain": "Pythagoras needs a right angle; a general triangle needs the sine or cosine rule."}'::jsonb),
('additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d:tf:f0346f7f', 'additional-maths', 'additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d', '5.5 Pythagoras and Trig in 2D and 3D', 'tf', 'tf', 1, '{"question": "The horizontal distance to a point, not the slant distance, is the adjacent side when finding the angle of elevation."}'::jsonb, '{"answer": true, "explain": "Elevation is measured from the horizontal, so the adjacent side must be the horizontal distance to the foot of the object."}'::jsonb),
('additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d:learn:8d0ab8b4', 'additional-maths', 'additional-maths:5-5-pythagoras-and-trig-in-2d-and-3d', '5.5 Pythagoras and Trig in 2D and 3D', 'learn', 'mcq', 1, '{"readingTitle": "How do you attack a 3D trigonometry problem?", "reading": "<p>Every 3D problem is really a <strong>2D problem in disguise</strong>. You never do trig in three dimensions at once — you find the correct <strong>right-angled triangle</strong> lying in one flat <strong>plane</strong>, draw it on its own, and solve it with Pythagoras and SOH-CAH-TOA.</p>\n            <ul>\n              <li><strong>Step 1 — find the triangle.</strong> Identify the two points you care about and the right angle that joins them (usually a vertical edge meeting a horizontal base).</li>\n              <li><strong>Step 2 — get a base length first.</strong> The side you need is often a <strong>diagonal across a horizontal base</strong>; find it with Pythagoras before you can find any angle.</li>\n              <li><strong>Step 3 — solve the 2D triangle.</strong> Redraw it flat, label opposite / adjacent / hypotenuse, then apply \\( \\sin,\\ \\cos \\) or \\( \\tan \\) (or the sine / cosine rules from 5.2 if the triangle is not right-angled).</li>\n            </ul>\n            <p>Work <strong>step by step</strong> and keep full accuracy in your calculator — round only the final answer. Everything on this page is in <strong>degrees</strong>.</p>", "question": "What is the sensible first move in most 3D trig problems?", "options": ["Find a right-angled triangle in one plane and redraw it in 2D", "Use the sine rule on the whole solid", "Round every length to the nearest whole number first", "Guess which angle looks about right"]}'::jsonb, '{"answer": 0, "explain": "3D problems are solved by isolating the correct right-angled triangle in one plane and treating it as an ordinary 2D triangle."}'::jsonb)
